class Solution {
    public int[] twoSum(int[] nums, int target) {
        int n = nums.length;

        for(int i = 0;i<n ;i++){
            for(int j = i+1;j<n;j++){
                if(nums[i]+nums[j]==target){
                    return new int[]{i,j};
                }
            }
        }
        return new int[]{-1};
    }
}

add-two-numbers.code:
/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public ListNode addTwoNumbers(ListNode l1, ListNode l2) {

        int carry = 0;
        ListNode fin = new ListNode();
        ListNode res = fin;

        while(l1 != null && l2 != null){
            int v = l1.val + l2.val + carry;
            if(v>9){
                carry = 1;
                v = v%10;
            }else{
                carry = 0;
            }
            res.next = new ListNode(v);
            l1 = l1.next;
            l2 = l2.next;
            res = res.next;
        }

        while(l1 !=null){
            int v = l1.val + carry;
            if(v>9){
                carry = 1;
                v = v%10;
            }else{
                carry = 0;
            }
            res.next = new ListNode(v);
            l1 = l1.next;
            res = res.next;
        }

        while(l2 !=null){
            int v = l2.val + carry;
            if(v>9){
                carry = 1;
                v = v%10;
            }else{
                carry = 0;
            }
            res.next = new ListNode(v);
            l2 = l2.next;
            res = res.next;
        }
        if(carry == 1){
            res.next = new ListNode(1);
            res = res.next;
        }

        return fin.next;

    }
}

longest-substring-without-repeating-char.code:
class Solution {
    public int lengthOfLongestSubstring(String s) {

        boolean[] vis = new boolean[1000];
        int l = 0;
        int r = 0;
        int n = s.length();
        int ans = 0;
        // s = s.trim();

        if(s.length()== 1){
            return 1;
        }

        while(r<n){

            while(vis[s.charAt(r)] == true){
                vis[s.charAt(l)] = false;
                l++;
            }

            ans = Integer.max(ans, r-l+1);
            vis[s.charAt(r)]=true;
            r++;
        } 
        return ans;
    }
}

