class Solution {
    public double findMedianSortedArrays(int[] nums1, int[] nums2) {

        int n = nums1.length;
        int m = nums2.length;

        int i = 0;
        int j = 0;

        int m1 = -1;
        int m2 = -1;

        for(int c = 0 ; c<=(n+m)/2; c++){
            m2 = m1;

            if(i!=n && j!=m){
                m1 = nums1[i]>nums2[j] ? nums2[j++]: nums1[i++];
            }
            else if(i<n){
                m1 = nums1[i++];
            }
            else{
                m1= nums2[j++];
            }
        }

        if((n+m)%2 == 0){
            return (m1+m2)/2.0;
        }else
            return m1;
    }
}

longest-palindromic-substring.code:
class Solution {
    public String longestPalindrome(String s) {

        int first = 0;
        int second = 1;
        int maxlen = 1;

        for(int i = 0; i<s.length();i++){

            // odd palindrome 
            int j = i;
            int k = i;
            while(j>=0 && k < s.length() && s.charAt(j) == s.charAt(k)){

                if(k-j+1 > maxlen){
                    first = j;
                    second = k+1;
                    maxlen = k-j+1;
                }
                j--;
                k++;
            }

            //even length
             j = i;
             k = i+1;
            while(j>=0 && k < s.length() && s.charAt(j) == s.charAt(k)){

                if(k-j+1 > maxlen){
                    first = j;
                    second = k+1;
                    maxlen = k-j+1;
                }
                j--;
                k++;
            }
        }
        return s.substring(first,second);
    }
}

container-with-most-water.code:
class Solution {
    public int maxArea(int[] arr) {
        int n = arr.length;
        int r = n-1;
        int l = 0;
        int ans = 0;
        while(l<=r){
            if(arr[l]>arr[r]){
                int index = r-l;
                ans = Integer.max(ans, arr[r]*index);
                r--;
            }else{
                int index = r-l;
                ans = Integer.max(ans,arr[l]*index);
                l++;
            }
        }
        return ans;
    }
}

3sum.code:
class Solution {
    public List<List<Integer>> threeSum(int[] nums) {
        Set<List<Integer>> set = new HashSet<>();
        int n = nums.length;
        for(int i = 0 ;i<n;i++){
            Set<Integer> subSet = new HashSet<>();
            for(int j = i+1;j<n;j++){
                int com = -nums[i]-nums[j];
                if(subSet.contains(com)){
                    List<Integer> sub = Arrays.asList(com,nums[i],nums[j]);
                    Collections.sort(sub);
                    set.add(sub);
                }
                subSet.add(nums[j]);
            }
        }
        return new ArrayList<>(set);
    }
}

