/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public ListNode removeNthFromEnd(ListNode head, int n) {
        ListNode curr = head;
        int k =0;
        while(curr!=null){
            curr = curr.next;
            k++;
        }

        int l = k-n;
        if(l == 0 ){
            return head.next;
        }
        curr = head;
        for(int i =1;i<l;i++){
            curr = curr.next;
        }
        curr.next = curr.next.next;
        return head;


    }

    private ListNode reverse(ListNode head){

        ListNode curr = head;
        ListNode prev = null;
        ListNode temp;

        while(curr != null){
            temp = curr.next;
            curr.next = prev;
            prev = curr;
            curr = temp;
        }
        return prev;
    }

}

valid-parentheses.code:
class Solution {
    public boolean isValid(String str) {
        Stack<Character> s = new Stack<>();
        int n = str.length();
        int i = 0;
        Set<Character> s1 = Set.of('(','{','[');
        Map<Character,Character> m = Map.of('(',')','{','}','[',']');
        while(i<n){
            if(s1.contains(str.charAt(i))){
                s.push(str.charAt(i));
            }else{
                if(!s.isEmpty() && str.charAt(i) == m.get(s.peek())){
                    s.pop();
                }else{
                    return false;
                }
            }

            i++;
        }
        return s.isEmpty() ? true:false;
    }
}

merge-two-sorted-lists.code:
/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public ListNode mergeTwoLists(ListNode list1, ListNode list2) {
        ListNode res = new ListNode();
        ListNode curr = res;
        while(list1 != null && list2 != null){
            if(list1.val <= list2.val){
                curr.next = new ListNode(list1.val);
                list1 = list1.next;
            }
            else{
                curr.next = new ListNode(list2.val);
                list2 = list2.next;
            }
            curr = curr.next;
        }

        while(list1 != null){
            curr.next = new ListNode(list1.val);
            list1 = list1.next;
            curr = curr.next;
        }
        while(list2 != null){
            curr.next = new ListNode(list2.val);
            list2 = list2.next;
            curr = curr.next;
        }

        return res.next;
    }

    private ListNode reverse(ListNode head){

        ListNode prev = null;
        ListNode curr = head;
        ListNode temp;

        while(curr != null){
            temp = curr.next;
            curr.next = prev;
            prev = curr;
            curr =temp;
        }
        return prev;
    }
}

