class Solution {
    public List<String> generateParenthesis(int n) {
        List<String> list = new ArrayList<>();
        generate(0,0,"",n,list);
        return list;

    }

    private void generate(int open, int close,String s, int n,List<String> list){

        if(n*2 == s.length()){
            list.add(s);
            return;
        }

        if(open<n){
            generate(open+1,close,s+"(",n,list);
        }
        if(close<open){
            generate(open,close+1,s+")",n,list);
        }
    }
}

merge-k-sorted-lists.code:
/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public ListNode mergeKLists(ListNode[] lists) {
        PriorityQueue<Integer> q = new PriorityQueue<>((i,j)->i-j);
        ListNode head = new ListNode();
        for(ListNode node : lists){
            while(node != null){
                q.offer(node.val);
                node = node.next;
            }
        }

        ListNode node = new ListNode();
        ListNode res = node;

        while(!q.isEmpty()){
            ListNode temp = new ListNode(q.poll());
            node.next = temp;
            node = node.next;
        }

        return res.next;

    }
}

