search-in-rotated-sorted-array.code:
class Solution {
    public int search(int[] nums, int target) {
        int pivot = findPivot(nums,0,nums.length-1);
        if(nums[pivot]==target){
            return pivot;
        }
        if (pivot == 0) {
            return binarySearch(nums, 0, nums.length - 1, target);
        }

        // Decide which side to search
        if (target >= nums[pivot] && target <= nums[nums.length - 1]) {
            return binarySearch(nums, pivot, nums.length - 1, target);
        } else {
            return binarySearch(nums, 0, pivot - 1, target);
        }
    }

    private int binarySearch(int[] arr, int l , int r,int target){

        while(l<=r){
            int m = l + (r-l)/2;
            if(arr[m] == target){
                return m;
            }
            if(arr[m]<target){
                l = m+1;
            }else{
                r=m-1;
            }
        }
        return -1;
    }
    private int findPivot(int[] arr, int lo, int hi) {
        while (lo <= hi) {
            if (arr[lo] <= arr[hi])
                return lo;

            int mid = (lo + hi) / 2;

            if (arr[mid] > arr[hi])
                lo = mid + 1;

            else
                hi = mid;
        }

        return lo;
    }
}

valid-sudoku.code:
class Solution {
    public boolean isValidSudoku(char[][] board) {

        int[][] row = new int[10][10];
        int[][] col = new int[10][10];
        int[][] sub = new int[10][10];
        for(int i=0; i<9; i++){
            for(int j = 0; j<9; j++){
                if(board[i][j]=='.'){
                    continue;
                }
                int val = board[i][j]-48;
                if(row[i][val]==1){
                    return false;
                }
                row[i][val]=1;
                if(col[j][val]==1){
                    return false;
                }
                col[j][val]=1;
                int subIn = (i/3)*3 + (j/3);
                if(sub[subIn][val]==1){
                    return false;
                }
                sub[subIn][val]=1;
            }
        }
        return true;
    }
}

combination-sum.code:
class Solution {
    public List<List<Integer>> combinationSum(int[] candidates, int target) {

        List<Integer> list = new ArrayList<>();
        List<List<Integer>> res = new ArrayList<>();
        comb(candidates,res,list,0,target,candidates.length);
        return res;

    }

    private void comb(int[] nums, List<List<Integer>> res, List<Integer> list , int i, int t,int n){

        if(t==0){
            res.add(new ArrayList<>(list));
            return;
        }

        if(t<0 || i>=n){
            return;
        }

        list.add(nums[i]);
        //single include
        comb(nums, res, list,i,t-nums[i],n);
        // exclude
        list.remove(list.size()-1);
        comb(nums,res,list,i+1,t,n);


    }
}

combination-sum-ii.code:
class Solution {
    public List<List<Integer>> combinationSum2(int[] candidates, int target) {

    Arrays.sort(candidates);
    List<List<Integer>> res = new ArrayList<>();
    List<Integer> list = new ArrayList<>();

    Set<List<Integer>> set = new HashSet<>();


        comb(candidates, res,list,0,target,candidates.length, set);
        return res;

    }


    private void comb(int[] arr, List<List<Integer>> res, List<Integer> list, int i, int t, int n, Set<List<Integer>> set){

        if(t == 0){
            Collections.sort(list);
            if(!set.contains(list)){
                res.add(new ArrayList<>(list));
                set.add(list);
            }
            return;
        }

        if(t<0 || i >= n){
            return ;
        }
        list.add(arr[i]);
        comb(arr,res,list,i+1,t-arr[i],n,set);
        list.remove(list.size()-1);
        while(i<n-1 && arr[i]==arr[i+1]){
            i++;
        }
        comb(arr,res,list,i+1,t,n,set);
    }
}

trapping-rain-water.code:
class Solution {
    public int trap(int[] arr) {

        int n = arr.length;
        int lmax = arr[0];
        int rmax = arr[n-1];
        int l = 1;
        int r = n-2;
        int ans = 0;
        while(l<=r){
            if(lmax>=rmax){
               ans+=Integer.max(0,rmax-arr[r]);
               rmax=Integer.max(rmax,arr[r]);
                r--;
            }else{
                ans+=Integer.max(0,lmax-arr[l]);
                lmax=Integer.max(lmax,arr[l]);
                l++;
            }
        }
        return ans;

    }
}

jump-game-ii.code:
class Solution {

    public int jump(int[] nums) {
        int[] val = new int[nums.length];
        Arrays.fill(val,-1);
        return countJump(0,nums,val);

    }

    private int countJump(int i ,  int[] nums, int[] val){

        if(i >=nums.length-1){
            return 0;
        }

       if(val[i]!=-1){
            return val[i];
       }
        int min = 1000000;

       for(int k = 1;k<=nums[i];k++){
            min= Math.min(min,1+countJump(i+k,nums,val));
       }
       return val[i]=min;

    }
}

permutations.code:
class Solution {
    public List<List<Integer>> permute(int[] nums) {

        List<List<Integer>> res = new ArrayList<>();
        getPermutation(nums,0,nums.length,res);
        return res;

    }

    private void getPermutation(int[] nums , int idx, int n , List<List<Integer>> res){

        if(idx == n){
            res.add(Arrays.stream(nums).boxed().collect(Collectors.toList()));
            return;
        }

        for(int i = idx ;i<n;i++){
            swap(i,idx,nums);
            getPermutation(nums,idx+1,n,res);
            swap(i,idx,nums);
        }
    }

    private void swap(int i , int idx, int[] nums){
        int temp = nums[i];
        nums[i]=nums[idx];
        nums[idx]=temp;
    }
}

