jump-game.code:
class Solution {
    public boolean canJump(int[] nums) {

        Boolean[] val = new Boolean[nums.length];

        return checkJump(0,nums,val);

    }

    private boolean checkJump(int i , int[] nums,Boolean[] val){

        if(i >= nums.length-1){
            return true;
        }

        if (nums[i]==0){
            return false;
        }
        if(val[i]!=null){
            return val[i];
        }

        for(int j = 1;j<=nums[i];j++){
            if(checkJump(i+j,nums,val)){
                return val[i]=true;
            }
        }

        return val[i]=false;
    }
}

unique-paths.code:
class Solution {
    public int uniquePaths(int m, int n) {

        int[][] dp = new int[m][n];
        for(int i = 0;i<m;i++){
            Arrays.fill(dp[i],-1);
        }
        return findpath(m-1,n-1,dp);

    }

    private int findpath(int i, int j, int[][] dp ){

        if(i == 0 && j == 0){
            return 1;
        }
        if(i<0 || j<0){
            return 0;
        }

        if(dp[i][j]!=-1){
            return dp[i][j];
        }

        int up = findpath(i-1,j,dp);
        int le = findpath(i,j-1,dp);
        return dp[i][j]=up+le;
    }
}

unique-paths-ii.code:
class Solution {
    public int uniquePathsWithObstacles(int[][] obstacleGrid) {
        int n = obstacleGrid.length;
        int m = obstacleGrid[0].length;


        int[][] dp = new int[n][m];
        for(int i =0 ;i<n; i++){
            Arrays.fill(dp[i],-1);
        }

        return findpath(n-1,m-1,obstacleGrid,dp);
    }

    private int findpath(int i,int j , int[][] arr,int[][] dp){

        if(i==0 && j==0){
            return arr[i][j] == 0 ? 1:0;
        }
        if(i<0 || j<0 || arr[i][j]==1){
            return 0;
        }

        if(dp[i][j]!=-1){
            return dp[i][j];
        }
        int up = findpath(i-1,j,arr,dp);
        int le = findpath(i,j-1,arr,dp);

        return dp[i][j]=up+le;
    }
}

