    public boolean exist(char[][] board, String word) {

        int n = board.length;
        int m = board[0].length;
        boolean[][] vis = new boolean[n][m];
        boolean res = false;

        for(int i =0;i<n;i++){
            for(int j = 0;j<m ;j++){
                if (board[i][j] == word.charAt(0)) {
                    res = res || findWord(i, j, 0, word, vis,board,n,m);
                    if(res)
                        return true;
                }
            }

        }
        return false;

    }

    private boolean findWord(int i ,int j, int s, String word , boolean[][] vis,char[][] board,int n, int m){

        if(s == word.length()){
            return true;
        }
        boolean res = false;

        if(i < 0 || i>= n || j<0 || j>=m || vis[i][j] || word.charAt(s) != board[i][j]){
            return false;
        }


        vis[i][j]= true;

        for(int k = 0 ;k<4 ;k++){
            int idx = i + rr[k];
            int idy = j + cc[k];
            res = res || findWord(idx,idy,s + 1,word,vis,board,n,m);     
        }
        vis[i][j]= false;

        return res;

    }
}

