class Solution {
    public int largestRectangleArea(int[] heights) {
        if(heights.length==1){
            return heights[0];
        }
        // if(heights.length ==2 ){
        //     return Integer.max(heights[0],heights[1]);
        // }
        int[] nse = nextSmallerElement(heights);
        int[] pse = previousSmallerElement(heights);

        // for(int i = 0;i<heights.length;i++){
        //     System.out.print(nse[i] + " "+ pse[i]);
        //     System.out.println();
        // }
        int ans =0;
        for(int i =0;i<heights.length; i++){
            int width = nse[i]-pse[i]-1;
            ans = Integer.max(ans,width*heights[i]);
        }

        return ans;
    }

    private int[] nextSmallerElement(int[] arr){
        int n = arr.length;
        Stack<Integer> q = new Stack<>();
        int[] ans = new int[arr.length];
        ans[n-1] = n;
        q.push(n-1);
        for(int i = n-2; i>=0; i-- ){
            while(!q.isEmpty() && arr[q.peek()]>=arr[i]){
                q.pop();
            }
            if(q.isEmpty()){
                ans[i]=n;
            }else{
                ans[i]=q.peek();
            }
            q.push(i);
        }

        Collections.reverse(Arrays.asList(ans));
        return ans;
    }

    private int[] previousSmallerElement(int[] arr){
        int n = arr.length;
        Stack<Integer> q = new Stack<>();
        int[] ans = new int[arr.length];
        ans[0] = -1;
        q.push(0);
        for(int i = 1; i<n; i++ ){
            while(!q.isEmpty() && arr[q.peek()]>arr[i]){
                q.pop();
            }
            if(q.isEmpty()){
                ans[i] = -1;
            }else{
                ans[i]=q.peek();
            }
            q.push(i);
        }

        return ans;
    }
}

