class Solution {

    int[] rr = {0,0,-1,1};
    int[] cc = {-1,1,0,0};

    public void solve(char[][] board) {

        int n = board.length;
        int m = board[0].length;

        int[][] vis = new int[n][m];

        for(int j=0; j<m; j++){
            if(board[0][j]=='O'){
                dfs(0,j,vis,board,n,m);
            }
        }

        for(int i=0; i<n; i++){
            if(board[i][0]=='O'){
                dfs(i,0,vis,board,n,m);
            }
        }

        for(int j=0; j<m; j++){
            if(board[n-1][j]=='O'){
                dfs(n-1,j,vis,board,n,m);
            }
        }

        for(int i=0; i<n; i++){
            if(board[i][m-1]=='O'){
                dfs(i,m-1,vis,board,n,m);
            }
        }

        for(int i=0;i<n;i++){
            for(int j = 0;j<m;j++){
                if(board[i][j]=='T'){
                    board[i][j]='O';
                }else{
                    board[i][j]='X';
                }
            }
        }



    }

    void dfs(int i, int j , int[][] vis, char[][] board, int n, int m){

        if(i<0 || j<0 || i>=n || j>=m || vis[i][j]==1){
            return;
        }
        vis[i][j]=1;
        board[i][j]='T';

        for(int k = 0;k<4;k++){
            int idx = rr[k]+i;
            int idy = cc[k]+j;

            if(idx>=0 && idy>=0 && idx<n && idy<m && board[idx][idy]=='O'){
                dfs(idx,idy,vis,board,n,m);
            }
        }


    }
}

palindrome-partitioning.code:
class Solution {
    public List<List<String>> partition(String s) {

        List<List<String>> res = new ArrayList<>();
        List<String> list = new ArrayList<>();
        getSubsets(0,s,s.length(),list,res);

        return res;
    }

    private void getSubsets(int idx,  String s, int n,List<String> list,List<List<String>> res){

        if(idx == n){
            res.add(new ArrayList<>(list));
            return;
        }

        for(int i = idx ; i<n ; i++){
            if (isPalindrome(s, idx, i)) {
                list.add(s.substring(idx, i + 1));   // choose
                getSubsets(i + 1, s,n, list, res);       // explore
                list.remove(list.size() - 1);         // unchoose (backtrack)
            } 
        }

    }

    private boolean isPalindrome(String s, int l, int r) {
        while (l < r) {
            if (s.charAt(l) != s.charAt(r)) 
                return false;
            l++;
            r--;
        }
        return true;
    }
}

