class Solution {
    public void reorderList(ListNode head) {

        ListNode slow = head;
        ListNode fast = head;

        while(fast != null && fast.next != null){
            slow = slow.next;
            fast = fast.next.next;
        }

        ListNode second = reverse(slow.next);
        slow.next = null;

        ListNode first = head;
        while(second != null){
            ListNode temp1 = first.next;
            ListNode temp2 = second.next;

            first.next = second;
            second.next = temp1;


            first = temp1;
            second = temp2;
        }

    }

    private int findlength(ListNode curr){
        int i =0;
        while(curr != null){
            curr = curr.next;
            i++;
        }
        return i;
    }


    private ListNode reverse(ListNode head){

        ListNode prev = null;
        ListNode curr = head;
        ListNode temp;

        while(curr!=null){
            temp = curr.next;
            curr.next = prev;
            prev = curr;
            curr =temp;
        }
        return prev;


    }
}

