class LRUCache {

    int capacity = 0;
    Map<Integer,Node> map= new HashMap<>();
    Node head;
    Node tail;
    int filled = 0;
    class Node {

        int val;
        int key;
        Node next;
        Node prev;

        Node(){

        }
        Node(int val,int key){
            this.val = val;
            this.key = key;
        }
    }

    public LRUCache(int capacity) {
        this.capacity = capacity;
        head = new Node(-1,-1);
        tail = new Node(-1,-1);
        head.next = tail;
        tail.prev = head;
    }

    public int get(int key) {

        if(map.containsKey(key)){
            Node node = map.get(key);
            int v = node.val;
            delete(node);
            add(node);
            return v;
        }else{
            return -1;
        }

    }

    public void put(int key, int value) {

        if(map.containsKey(key)){
            Node node = map.get(key);
            delete(node);
            Node newNode = new Node(value,key);
            add(newNode);
            map.put(key,newNode);
        }else{
            Node node = new Node(value,key);
            map.put(key,node);
            add(node);
            filled++;
            if(filled > capacity){
                Node nodeToDelete = tail.prev;
                delete(nodeToDelete);
                map.remove(nodeToDelete.key);
            }
        }

    }

    public void add(Node node){

        Node temp = head.next;
        head.next = node;
        node.prev = head;
        node.next = temp;
        temp.prev = node;
    }

    public void delete(Node node){
        Node next = node.next;
        Node prev = node.prev;
        prev.next = next;
        next.prev = prev;
    }




}

