class Solution {
    public int[] twoSum(int[] arr, int target) {
        int n = arr.length;
        int l = 0;
        int r = n-1;

        while(l<r){
            if(arr[l]+arr[r] == target){
                return new int[]{l+1,r+1};
            }
            if(arr[l]+arr[r]<target){
                l++;
            }else{
                r--;
            }
        }
        return new int[]{-1};
    }
}

