class Solution {
    public void rotate(int[] nums, int k) {

        if( k > nums.length)
            k= k % nums.length;

        nums = reverse(nums,nums.length-1,nums.length-k);
        nums = reverse(nums,nums.length-1-k,0);
        nums = reverse(nums, nums.length-1,0);


    }

    private int[] reverse(int num[], int start, int end){
        while(start > end ){
            int temp = num[start];
            num[start] = num[end];
            num[end] = temp;
            start --;
            end ++;
        }
        return num;
    }
}

