class Solution {
    public int rob(int[] nums) {

        int n = nums.length;
        if(n==1){
            return nums[0];
        }
        int[] dp = new int[n];
        Arrays.fill(dp,-1);
        getmax(n-1,dp,nums);
        return dp[n-1];

    }

    private int getmax(int i, int[] dp, int[] arr){

        if(i == 0 ){
            return arr[i];
        }
        if(i<0){
            return 0;
        }

        if(dp[i]!=-1){
            return dp[i];
        }

        int pick = getmax(i-2, dp, arr) + arr[i];

        int notpick = getmax(i-1,dp,arr);

        return dp[i]=Integer.max(pick,notpick);
    }
}

