    public int kthSmallest(TreeNode root, int k) {
       addToQueue(root);

       while(k>1){
        q.poll();
        k--;
       }

    return q.peek();

    }

    private void addToQueue(TreeNode root){
        if(root == null){
            return;
        }
        addToQueue(root.left);
        if(root !=null){
            q.offer(root.val);
        }
        addToQueue(root.right);
    }
}

