class Solution {
    public int[] maxSlidingWindow(int[] nums, int k) {
        PriorityQueue<int[]> q = new PriorityQueue<>((i,j)->j[0]-i[0]);
        int n = nums.length;
        int[] res = new int[n-k+1];
        for(int i =0;i<k;i++){
            q.offer(new int[]{nums[i],i});
        }

        res[0] = q.peek()[0];

        for(int i = k; i<n ;i++){
            q.offer(new int[]{nums[i],i});
            while(!q.isEmpty() && q.peek()[1]<=i-k){
                q.poll();
            }
            res[i-k+1]=q.peek()[0];
        }
        return res;


    }
}

