        Stack<Integer> s = new Stack<>();

        int[] res = new int[n];

        for(int i = n-1; i>=0;i--){

            while(!s.isEmpty() && nums[i]>=s.peek()){
                s.pop();
            }

            if(s.isEmpty()){
                res[i] = nextGFromF(nums,nums[i]);

            }else{
                res[i]=s.peek();
            }
            s.push(nums[i]);
        }

        return res;

    }

