class Solution {
    public boolean checkInclusion(String s1, String s2) {

        int[] charArr = new int[26];

        int dist = 0;

        for(char c : s1.toCharArray()){
            charArr[c-'a']++;
            if(charArr[c-'a']==1){
                dist++;
            }
        }

        int n = s1.length();
        int m = s2.length();

        for(int i = 0;i<m; i++){
            char ch = s2.charAt(i);
            charArr[ch-'a']--;
            if(charArr[ch-'a']==0){
                dist--;
            }

            if(i>=n){
                char cl = s2.charAt(i-n);
                charArr[cl-'a']++;
                if(charArr[cl-'a']==1){
                    dist++;
                }
            }

            if(dist == 0){
                return true;
            }
        }
        return false;
    }
}

