        ans[n-1]=0;
        stack.push(n-1);
        for(int i=n-2; i>=0; i--){
            while(!stack.isEmpty() && temp[stack.peek()]<=temp[i]){
                stack.pop();
            }
            if(!stack.isEmpty()){
                ans[i]=stack.peek()-i;
            }else{
                ans[i]=0;
            }
            stack.push(i);
        }

        Collections.reverse(Arrays.asList(ans));
        return ans;
    }
}

