class Solution:
    def isNStraightHand(self, hand, groupSize) :
        if len(hand) % groupSize != 0:
            return False

        count = collections.Counter(hand)
        keys = sorted(list(count.keys()))

        for card in keys:
            if count[card] == 0:
                continue
            total = count[card]
            for n in range(card + 1, card + groupSize):
                count[n] -= total
                if count[n] < 0:
                    return False
            count[card] -= total

        return True

