rotting-oranges.code:
class Solution {

    int[] rr = {0,0,-1,1};
    int[] cc = {-1,1,0,0};
    public int orangesRotting(int[][] grid) {
        int n = grid.length;
        int m = grid[0].length;

        int[][] vis = new int[n][m];
        Queue<List<Integer>> queue = new LinkedList<>();

        for(int i=0; i<n; i++){
            for(int j=0; j<m; j++ ){
                if(grid[i][j] == 2){
                    queue.offer(List.of(i,j));
                }
            }
        }

        int ans = bfs(queue,grid,n,m);
        for(int i=0; i<n; i++){
            for(int j=0; j<m; j++ ){
                if(grid[i][j] == 1){
                    return -1;
                }
            }
        }
        return ans;
    }


    private int bfs(Queue<List<Integer>> queue,int[][] grid, int n , int m){
        int ans = 0;

        while(!queue.isEmpty()){
            int size = queue.size();
                boolean flag = false;

            for (int s = 0; s < size; s++){
                List<Integer> list = queue.poll();
                int i = list.get(0);
                int j = list.get(1);

                for(int k=0; k<4; k++){
                    int idx = rr[k] + i;
                    int idy = cc[k] + j;

                    if(idx >=0 && idx<n && idy >=0 && idy<m && grid[idx][idy] == 1){
                        flag = true;
                        grid[idx][idy] = 2;
                        queue.offer(List.of(idx,idy));
                    }
                }
            }
            if(flag)
            ans++;

        }

        return ans;
    }
}

