class Solution {
    public long getDescentPeriods(int[] prices) {
        int end = 0;
        int start =0;
        long res =1;

        for(end = 1; end<prices.length ; end++){
            if(prices[end]==prices[end-1] - 1){
                res = res + end - start + 1;
            }
            else{
                start = end;
                res = res + end - start + 1;
            }
        }
        return res;
    }
}

