class Solution {
    public int maxCount(int[] banned, int n, int maxSum) {
        int res = 0; 
        long sum = 0;
        for(int i = 1;i <= n ; i++ ){
            boolean exist = findNumberExistInArray(i,banned);
            if(!exist){
                sum+=i;
                if(sum<=maxSum)
                    res+=1;
            }
        }
        return res;
    }

    private boolean findNumberExistInArray(int m,int[] banned){
        for(int j=0 ; j< banned.length ; j++){
            if(banned[j]==m)
                return true;
        }
        return false;
    }
}

